type": "text", "marks": [{"type": "bold"}], "text": "Result: "}, {"type": "text", "text": "More leads from the same ad budget, and you're live often this very week."}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What's included"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A mobile-friendly page"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A sharp message and a clear call to action"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A lead or contact form"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Basic SEO"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Analytics and pixel tracking"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Value and ROI"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "From SEK 9,000 you get a page that makes every ad krona land somewhere that actually sells."}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Objections for this package"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "\"Isn't our regular site enough?\""}]}, {"type": "paragraph", "content": [{"type": "text", "text": "A regular site has many exits and distractions. A landing page has a single goal and therefore converts far better on ad traffic."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "\"It feels too small.\""}]}, {"type": "paragraph", "content": [{"type": "text", "text": "That's exactly the point – you start small and build on when it delivers. The page can grow into a full website later."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Close"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Shall we set up your first page so you start capturing leads right away?"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Price"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "From SEK 9,000. Can be expanded into a full business website."}]}]}$j$::jsonb,
    body_es = $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Cuándo usarla"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Para clientes que quieren probar una idea, lanzar una campaña o captar leads rápido: una única página enfocada y construida para convertir."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Apertura (gancho)"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿Queréis probar algo rápido o captar más leads de vuestros anuncios? Entonces el inicio más inteligente es una página afilada con un solo objetivo."}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Preguntas de calificación"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿A dónde enviáis vuestro tráfico de anuncios hoy?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿Qué queréis que haga el visitante en la página?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿Con qué rapidez queréis estar en línea?"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "El pitch"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Problema: "}, {"type": "text", "text": "Si envías tráfico a una web desordenada pierdes a la mayoría de visitantes antes de que hagan nada."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Solución: "}, {"type": "text", "text": "Una página de aterrizaje es una sola página con un mensaje claro y un objetivo: que el visitante contacte o compre