ype": "paragraph", "content": [{"type": "text", "text": "Ese es justo el punto: empezáis con poco y ampliáis cuando da resultados. La página puede crecer hasta ser una web completa después."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Cierre"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿Montamos vuestra primera página para que empecéis a captar leads ya?"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Precio"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Desde 9 000 SEK. Se puede ampliar a una web corporativa completa."}]}]}$j$::jsonb
FROM public.training_categories cat
WHERE ti.category_id = cat.id AND cat.slug = 'saljmanus'
  AND ti.title = 'Säljguide: Landningssida';

