UPDATE public.training_items ti
SET title_en = 'Sales guide: MVP',
    title_es = 'Guía de ventas: MVP',
    body_en = $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "When to use it"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "For startups and companies that have a product idea but want to validate it with real users before investing big."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Opening (hook)"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Do you have a product idea but don't want to spend hundreds of thousands before you know it works?"}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qualifying questions"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "What's the core of the idea – what must it absolutely do?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Who is the first user you want to test on?"}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "What happens if you wait six months to launch?"}]}]}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "The pitch"}]}, {"type": "bulletList", "content": [{"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Problem: "}, {"type": "text", "text": "The biggest risk is building a large, expensive product nobody wants."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Solution: "}, {"type": "text", "text": "An MVP is a working first version with only the core features, built to be tested on real users."}]}]}, {"type": "listItem", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "